+    let max_phi = all_phis.iter().cloned().fold(0.0f64, f64::max).max(1e-10);
+
+    // Draw grouped bars: normal (blue) and cancer (red) for each module + full
+    let n_groups = results.normal_module_phis.len() + 1; // +1 for "Full"
