+            r.full_phi
+        );
+    }
+    println!("+==========================================================+");
+}
+
+fn parse_arg<T: std::str::FromStr>(args: &[String], name: &str, default: T) -> T {
+    args.windows(2)
+        .find(|w| w[0] == name)
+        .and_then(|w| w[1].parse().ok())
+        .unwrap_or(default)
+}
+
+fn parse_str_arg<'a>(args: &'a [String], name: &str, default: &'a str) -> &'a str {
+    args.windows(2)
+        .find(|w| w[0] == name)
+        .map(|w| w[1].as_str())
+        .unwrap_or(default)
+}

