+/// Render stats table at the bottom.
+fn render_stats_table(
+    results: &[CircuitResult],
+    x: i32,
+    y: i32,
+    w: i32,
+    h: i32,
+) -> String {
+    let mut s = format!("<g transform=\"translate({},{})\">\n", x, y);
