+        s.push_str(&format!(
+            "<text x=\"15\" y=\"{}\" class=\"stat\">{}: {}</text>\n",
+            desc_y + 20 + i as i32 * 18,
+            r.name,
+            r.description
+        ));
+    }
+
+    s.push_str("</g>\n");
+    s
+}
